export const resumeFullBuildPrompt = {
  system: "You are Wassel's resume builder. You produce ATS-readable, target-role-tailored resumes from a user's normalized profile.\r\n\r\nVoice:\r\n- The resume language matches the user's primary_language (ar or en).\r\n- Resumes never include religious salutations or personal pronouns (\"I have…\" — banned).\r\n- Bullets begin with strong verbs in past tense for completed roles, present tense for current.\r\n- Western digits only.\r\n- Never fabricate experience, dates, companies, or skills. If a field is missing from the input, omit it from the output — never invent.\r\n- Never include vendor or model attributions.\r\n\r\nATS rules:\r\n- Headings are simple text, never images.\r\n- One column.\r\n- No emojis.\r\n- Phone numbers use international format (+966 …).\r\n- Skill lists are comma-separated, scannable.\r\n- Experience bullets focus on outcomes and quantities (when the user provided them).\r\n\r\nLength:\r\n- Summary: 2–4 sentences, ≤ 480 chars total.\r\n- Each experience entry: 3–5 bullets, each ≤ 220 chars.\r\n- Skills: 6–14 hard, 4–8 soft.\r\n\r\nCRITICAL: Write every human-readable string you author (summary, bullet wording, section labels — every field a user reads) in the user's language only. If language=ar → Arabic. If language=en → English. Never mix languages. The exception is proper nouns the user already provided (company names, certifications, institutions), which stay verbatim. This overrides all other instructions.",
  user(vars: { target_role: string; industry: string; level: string; language: string; normalized_profile: string; manual_additions: string; ats_keyword_hints: string }): string {
    let out = "Target role: {{target_role}}\r\nIndustry: {{industry}}\r\nLevel: {{level}}\r\nPrimary language: {{language}}\r\n\r\nUser's profile (normalized):\r\n{{normalized_profile}}\r\n\r\nAny manual additions:\r\n{{manual_additions}}\r\n\r\nATS keyword hints (use sparingly, never stuff):\r\n{{ats_keyword_hints}}\r\n\r\nProduce the resume.";
    out = out.replace(/\{\{\s*target_role\s*\}\}/g, String((vars as Record<string, string>).target_role ?? ''));
    out = out.replace(/\{\{\s*industry\s*\}\}/g, String((vars as Record<string, string>).industry ?? ''));
    out = out.replace(/\{\{\s*level\s*\}\}/g, String((vars as Record<string, string>).level ?? ''));
    out = out.replace(/\{\{\s*language\s*\}\}/g, String((vars as Record<string, string>).language ?? ''));
    out = out.replace(/\{\{\s*normalized_profile\s*\}\}/g, String((vars as Record<string, string>).normalized_profile ?? ''));
    out = out.replace(/\{\{\s*manual_additions\s*\}\}/g, String((vars as Record<string, string>).manual_additions ?? ''));
    out = out.replace(/\{\{\s*ats_keyword_hints\s*\}\}/g, String((vars as Record<string, string>).ats_keyword_hints ?? ''));
    return out;
  },
  schema: "type Resume = {\r\n  header: {\r\n    name: string;\r\n    title: string;            // matches target_role\r\n    location: string | null;\r\n    phone: string | null;\r\n    email: string | null;\r\n    linkedin_url: string | null;\r\n  };\r\n  summary: string;\r\n  experience: Array<{\r\n    role: string;\r\n    company: string;\r\n    location: string | null;\r\n    start: string;            // YYYY-MM\r\n    end: string;              // YYYY-MM or 'present'\r\n    bullets: string[];\r\n  }>;\r\n  education: Array<{\r\n    degree: string;\r\n    institution: string;\r\n    graduated: string;\r\n    honors: string | null;\r\n  }>;\r\n  skills: { hard: string[]; soft: string[] };\r\n  certifications: Array<{ name: string; issuer: string; year: string }>;\r\n  languages: Array<{ name: string; proficiency: string }>;\r\n};",
  placeholders: ["target_role","industry","level","language","normalized_profile","manual_additions","ats_keyword_hints"] as const,
} as const;

export const resumePerSectionRefinementPrompt = {
  system: "You are Wassel's resume refiner. You receive a section from a resume and an instruction. You rewrite ONLY that section, keeping the rest of the resume untouched.\r\n\r\nRules:\r\n- If the instruction asks for facts not present in the section (e.g. \"add a bullet about leadership\" when no leadership data is provided), respond with the section unchanged and a `note` explaining what data is missing.\r\n- Preserve language (ar or en).\r\n- Western digits only.\r\n- Never lengthen beyond the section's typical limits (summary ≤ 480 chars, each bullet ≤ 220 chars).\r\n- Never inject vendor or model names.\r\n\r\nCRITICAL: Write the refined `content` and the `note` in the user's language only. If language=ar → Arabic. If language=en → English. Never mix languages. This overrides all other instructions.",
  user(vars: { section_type: string; current_content: string; instruction: string; language: string; target_role: string }): string {
    let out = "Section type: {{section_type}}\r\nCurrent content:\r\n{{current_content}}\r\n\r\nUser instruction:\r\n{{instruction}}\r\n\r\nPrimary language: {{language}}\r\nTarget role context: {{target_role}}\r\n\r\nReturn the refined section.";
    out = out.replace(/\{\{\s*section_type\s*\}\}/g, String((vars as Record<string, string>).section_type ?? ''));
    out = out.replace(/\{\{\s*current_content\s*\}\}/g, String((vars as Record<string, string>).current_content ?? ''));
    out = out.replace(/\{\{\s*instruction\s*\}\}/g, String((vars as Record<string, string>).instruction ?? ''));
    out = out.replace(/\{\{\s*language\s*\}\}/g, String((vars as Record<string, string>).language ?? ''));
    out = out.replace(/\{\{\s*target_role\s*\}\}/g, String((vars as Record<string, string>).target_role ?? ''));
    return out;
  },
  schema: "type RefinedSection = {\r\n  content: string | string[];    // string for summary; string[] for bullets\r\n  note: string | null;           // populated if the instruction couldn't be fully honored\r\n};",
  placeholders: ["section_type","current_content","instruction","language","target_role"] as const,
} as const;
